// Extract the optimized prompt and explanation from the API response
const response = $input.item.json;

return {
  json: {
    original_prompt: response.rawText ? response.rawText.split('---EXPLANATION---')[0].replace(/---SCORE---\d+---/g, '').trim() : '',
    optimized_prompt: response.optimizedText || '',
    explanation: response.explanation || '',
    changes: response.changes || '',
    mode: $('Set Input Parameters').item.json.mode,
    provider: response.provider || $('Set Input Parameters').item.json.provider,
    model: response.model || ''
  }
};
